// Group candidates that share the same speaker_id and have overlapping key_label prefixes
const candidates = $input.all().map(i => i.json);
const clusters = {};
candidates.forEach(c => {
  const clusterKey = c.speaker_id + ':' + c.key_label.split('.')[0];
  if (!clusters[clusterKey]) clusters[clusterKey] = [];
  clusters[clusterKey].push(c);
});

return Object.values(clusters).map(group => ({
  json: {
    speaker_id: group[0].speaker_id,
    cluster_key: group[0].key_label.split('.')[0],
    candidates: group,
    needs_llm_consolidation: group.length > 1
  }
}));

// Process ALL clusters — output one item per cluster
// Embed fallback data in every item so Parse LLM Output never needs back-references
const allClusters = $input.all().map(i => i.json);

return allClusters.map(cluster => {
  const c = cluster.candidates[0];
  const fallbackText  = c.key_label + ': ' + (c.all_values || '').split(' ||| ')[0];
  const fallbackConf  = parseFloat(c.computed_confidence) || 0.75;

  if (!cluster.needs_llm_consolidation) {
    return { json: {
      speaker_id:  cluster.speaker_id,
      key_label:   c.key_label,
      claim_text:  fallbackText,
      confidence:  fallbackConf,
      _needs_llm:  false
    }};
  }

  const body = {
    model: 'anthropic/claude-haiku-4-5',
    temperature: 0.0,
    max_tokens: 400,
    messages: [
      {
        role: 'system',
        content: 'You are consolidating possibly-duplicate profile facts about the same person.\nGiven a list of observed facts, merge duplicates and resolve contradictions.\nReturn a JSON array of final claims: [{"key_label": "...", "claim_text": "key: value", "confidence": 0.0-1.0}]\nIf facts contradict each other, keep the most recent with lower confidence.\nNever return more claims than you received candidates.'
      },
      {
        role: 'user',
        content: 'Candidates to consolidate:\n' + JSON.stringify(
          cluster.candidates.map(c => ({ key: c.key_label, value: c.all_values })), null, 2
        )
      }
    ]
  };

  return { json: {
    body,
    speaker_id:  cluster.speaker_id,
    key_label:   c.key_label,
    claim_text:  fallbackText,
    confidence:  fallbackConf,
    _needs_llm:  true
  }};
});

// Process LLM responses for multi-candidate clusters
// HTTP Request node replaces item with response body — speaker_id is lost.
// Recover original metadata by matching back to Build Consolidation Request items.
const responses = $input.all();

// Get only the _needs_llm:true originals, in order — these map 1:1 to LLM responses
const llmOriginals = $('Build Consolidation Request').all()
  .filter(item => item.json._needs_llm === true)
  .map(item => item.json);

const results = [];

for (let i = 0; i < responses.length; i++) {
  const item = responses[i].json;
  const orig = llmOriginals[i] || {};

  const speaker_id = orig.speaker_id;
  const key_label  = orig.key_label;
  const fallback   = orig.claim_text;
  const fallbackConf = orig.confidence || 0.5;

  // LLM error or no choices — use embedded fallback data
  if (item.error || !item.choices) {
    results.push({ json: { speaker_id, key_label, claim_text: fallback, confidence: fallbackConf }});
    continue;
  }

  // Parse LLM JSON response
  let pushed = false;
  try {
    const text = item.choices[0]?.message?.content || '[]';
    const claims = JSON.parse(text);
    if (Array.isArray(claims) && claims.length > 0) {
      claims.forEach(c => results.push({ json: {
        speaker_id,
        key_label:  c.key_label,
        claim_text: c.claim_text,
        confidence: c.confidence || 0.75
      }}));
      pushed = true;
    }
  } catch(e) {}

  if (!pushed) {
    results.push({ json: { speaker_id, key_label, claim_text: fallback, confidence: fallbackConf }});
  }
}

return results;

